func ptr(s string) *string { return types.Pointer(s) }

// goals is a 0..99 integer score field (nullable; not Required so unplayed
// matches and partial predictions are valid).
func goals(name string) *core.NumberField {
	return &core.NumberField{
		Name:    name,
		Min:     types.Pointer(0.0),
		Max:     types.Pointer(99.0),
		OnlyInt: true,
	}
}

