func down0001(app core.App) error {
	for _, name := range []string{
		nAppMeta, nForecastScores, nMatchScores, nForecasts, nTips,
		nLeagueMembers, nLeagues, nScoringConfigs, nMatches, nGroups, nTeams,
	} {
		if c, err := app.FindCollectionByNameOrId(name); err == nil {
			if err := app.Delete(c); err != nil {
				return err
			}
		}
	}
	return nil
}
